  fetchSecurityPolicyService(resp) {
    
    if (resp) {
      this.securityData = resp;
      console.log(this.securityData);
      this.assignCheckValue(this.securityData);
      if (this.securityData.recordStatus == 'O' || this.securityData.recordStatus == 'Open') {
        this.securityData.recordStatus = 'OPEN';
      } else if (this.securityData.recordStatus == 'C' || this.securityData.recordStatus == 'Close') {
        this.securityData.recordStatus = 'CLOSE';
      }
      if (this.securityData.authStatus == 'A' || this.securityData.authStatus == 'Authorized' ) {
        this.securityData.authStatus = 'AUTHORIZED';
      } else if (this.securityData.authStatus == 'U' || this.securityData.authStatus == 'Unauthorized' ) {
        this.securityData.authStatus = 'UNAUTHORIZED';
      }
      if (this.securityData.firstTimeAuth == 'Y') {
        this.securityData.firstTimeAuth = 'YES';
      } else if (this.securityData.firstTimeAuth == 'N') {
        this.securityData.firstTimeAuth = 'NO';
      }
    }
  }
  // async pageDeactivation(): Promise<Observable<boolean>> {
  pageDeactivation(): Observable<boolean> {
    console.log('pageDeactivation in user was called');
    // return of (true);
    if (this.securityForm.touched && this.formTouched == true) {
      let swalMsg: string = '';
      const result = confirm(
        'There are unsaved changes in the screen.Would you like to navigate to other screen?'
      );
      console.log('result: ', result);
      return of(result);
    } else {
      return of(true);
    }
  }
      
       
  reset() {
    this.securityForm.reset();
  }
  editValues() {
    this.edit = true;
  }

  activeEditOnInit() {
    if (this.securityForm.value.activeEdit) {
      this.editValues();
    }
  }

  auth() {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Authorize record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        if (
          this.securityData.createdBy === localStorage.getItem('userFromLogin')
        ) {
          Swal.fire({ text: 'Maker Cannot Authorize Record!', icon: 'error' });
          return;
        }
        console.log('this is authorzation');
        this.securityForm.value.loggedInUser = this.currentUser;
        this.secuityService
          .authSecurity('authorize', this.securityForm.value)
          .subscribe(
            (resp) => {
              console.log(resp);
              this.securityData = resp;
              this.auditlog();
              if (resp) {
                Swal.fire({
                  text: 'Record is Authorized',
                  icon: 'success',
                });
              }
            },
            (error) => {
              Swal.fire({ text: error.error.message, icon: 'error' });
            }
          );
      }
    });
  }
  close() {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Close record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        console.log('this is close');
        this.secuityService
          .authSecurity('close', this.securityForm.value)
          .subscribe(
            (resp) => {
              console.log(resp);
              this.securityData = resp;
              this.auditlog();
              if (this.securityData) {
                Swal.fire({ text: 'Record is Closed' });
              }
            },
            (error) => {
              Swal.fire(error.error.message);
            }
          );
      }
    });
  }

  reopen() {
    Swal.fire({
      //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
      text: 'You are trying to Reopen record. ' + ' Do you want to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3e54b8',
      cancelButtonColor: '#d33',
      // confirmButtonText: 'PROCEED.'
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
      iconColor: '#d33',
    }).then((result) => {
      console.log('this is reopen ', result);
      if (result.isConfirmed === true) {
        this.secuityService
          .authSecurity('reopen', this.securityForm.value)
          .subscribe(
            (resp) => {
              console.log(resp);
              this.securityData = resp;
              this.auditlog();

              if (this.securityData.recordStatus == 'O') {
                this.auditlog();
                Swal.fire({
                  text: 'Record is Reopened',
                });
              } else {
                Swal.fire({ text: 'Record cannot be opened ' });
              }
            },
            (error) => {
              Swal.fire(error.error.message);
            }
          );
      }
    });
  }
  auditlog() {
    if (this.securityData.recordStatus == 'O') {
      this.securityData.recordStatus = 'OPEN';
    } else if (this.securityData.recordStatus == 'C') {
      this.securityData.recordStatus = 'CLOSE';
    }
    if (this.securityData.authStatus == 'A' || this.securityData.authStatus == 'Authorized' ) {
      this.securityData.authStatus = 'AUTHORIZED';
    } else if (this.securityData.authStatus == 'U' || this.securityData.authStatus == 'Unauthorized' ) {
      this.securityData.authStatus = 'UNAUTHORIZED';
    }
    if (this.securityData.firstTimeAuth == 'Y') {
      this.securityData.firstTimeAuth = 'YES';
    } else if (this.securityData.firstTimeAuth == 'N') {
      this.securityData.firstTimeAuth = 'NO';
    }
  }
  exit() {
    localStorage.removeItem('securityPolicyData');
  }
  canExit() : Promise<boolean> {
    let isExit :boolean = false;
    if (this.securityForm.touched && this.formTouched==true) {
    return Swal.fire({ 
      text: 'There are unsaved changes in the screen. Would you like to navigate to other screen?',
      showCancelButton: true,
      confirmButtonColor: '#E6224A',
      cancelButtonColor: '#011945',
      cancelButtonText: 'NO',
      confirmButtonText: 'YES',
      icon: 'info',
    }).then((result) => {
      if (result.isConfirmed === true) {
        isExit=true;
        this.cdr.markForCheck();
           return isExit;
      }
      else{
        isExit=false;
        this.cdr.markForCheck();
        return isExit;
      }
    
    });
  }
 else{
  isExit=true;
  return new Promise((resolve, reject) => {
    if (isExit === true) {
      isExit=true;
      this.cdr.markForCheck();
      resolve(true);
    }
  
  })
 }
    }
