import { ChangeDetectorRef, Component, OnInit, ViewChild } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { RoleService } from 'src/app/shared/services/role.service';
import { SecurityPolicyService } from 'src/app/shared/services/security-policy.service';
import { DataTableDirective } from 'angular-datatables';
import { UsersService } from 'src/app/shared/services/user.service';
import { ApiService } from 'src/app/shared/services/api.service';
import Swal from 'sweetalert2';
import { Route } from '@angular/router';
import { analyzeAndValidateNgModules, Version } from '@angular/compiler';

interface DataTableConfigProps {
  sortBy: string;
  pageSize: number;
  pageNo: number;
}

@Component({
  selector: 'npr-security-policy-summary',
  templateUrl: './security-policy-summary.component.html',
  styleUrls: ['./security-policy-summary.component.scss'],
})
export class SecurityPolicySummaryComponent implements OnInit {
  @ViewChild(DataTableDirective, { static: false })
  dtElement: DataTableDirective;

  respArray: any[] = [];
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();

  deleteStatusFlag: boolean;
  ModifyUser: any;
  maxVersion: any;
  dataTableConfig: DataTableConfigProps = {
    sortBy: 'version',
    pageNo: 1,
    pageSize: 5,
  };
  tableListenerInitialized: boolean;
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];

  constructor(
    private apiService: SecurityPolicyService,
    private roleService: RoleService,
    private router: Router,
    private cdr: ChangeDetectorRef,
    private userApi: UsersService
  ) {}

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [5] }],
      order: [[0, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, -1],
        [5, 10, 20, 30],
      ],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],
    };
    this.getDataForMonitor();
    this.roleService.fetchScreenPermissions('Security Policy');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }

  getDataForMonitor() {
    this.isLoading = true;
    this.respArray = [];
    this.apiService
      .getAllSecurityPolicy(
        this.dataTableConfig.pageNo,
        this.dataTableConfig.pageSize,
        this.dataTableConfig.sortBy
      )
      .subscribe(async (dataresp) => {
        for (let item of dataresp.result) {
          item.authStatus = this.statusArr.find((i) =>
            i.startsWith(item.authStatus)
          );

          item.recordStatus = this.statusArr.find((i) =>
            i.startsWith(item.recordStatus)
          );
        }
        this.maxVersion = Math.max.apply(
          Math,
          dataresp.result.map(function (o) {
            return o.version;
          })
        );
        this.respArray = dataresp.result;
        // await new Promise(resolve => setTimeout(resolve, 2000));
        this.isLoading = false;
        this.cdr.markForCheck();
        this.dtTrigger.next();
        // this.initDataTableListeners()
      });
  }
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }

  new() {
    this.router.navigateByUrl('/security-policy');
  }
  getResp() {
    localStorage.removeItem('securityPolicyData');
    this.router.navigateByUrl('/security-policy');
    let data = this.respArray.find((item) => item.version == this.maxVersion);
    console.log(this.respArray.find((item) => item.version == this.maxVersion));
    this.apiService.setSecurityPolicy({
      authStatus: data.authStatus,
      authorizedBy: data.authorizedBy,
      authorizedTime: data.authorizedTime,
      createdBy: data.createdBy,
      createdDate: data.createdDate,
      isActive: data.isActive,
      maxInvLogins: data.maxInvLogins,
      maxPswdLength: data.maxPswdLength,
      minPswdLength: data.minPswdLength,
      modifiedBy: data.modifiedBy,
      modifiedTime: data.modifiedTime,
      firstTimeAuth: data.firstTimeAuth,
      notifyPasswordExpiryInDays: data.notifyPasswordExpiryInDays,
      pswdComplexLcase: data.pswdComplexLcase,
      pswdComplexNum: data.pswdComplexNum,
      pswdComplexSplc: data.pswdComplexSplc,
      pswdComplexUcase: data.pswdComplexUcase,
      pswdExpiry: data.pswdExpiry,
      pswdReuseAft: data.pswdReuseAft,
      recordStatus: data.recordStatus,
      version: data.version,
      passwordGenerationType: data.passwordGenerationType,
    });
    localStorage.setItem('securityPolicyData', JSON.stringify(data));
  }

  gotoSummary() {
    this.router.navigateByUrl('/security-policy');
    let data = this.respArray.find((item) => item.version == this.maxVersion);
    console.log(this.respArray.find((item) => item.version == this.maxVersion));
    this.apiService.setSecurityPolicy({
      activeEdit: true,
      authStatus: data.authStatus,
      authorizedBy: data.authorizedBy,
      authorizedTime: data.authorizedTime,
      createdBy: data.createdBy,
      createdDate: data.createdDate,
      isActive: data.isActive,
      maxInvLogins: data.maxInvLogins,
      maxPswdLength: data.maxPswdLength,
      minPswdLength: data.minPswdLength,
      modifiedBy: data.modifiedBy,
      modifiedTime: data.modifiedTime,
      firstTimeAuth: data.firstTimeAuth,
      notifyPasswordExpiryInDays: data.notifyPasswordExpiryInDays,
      pswdComplexLcase: data.pswdComplexLcase,
      pswdComplexNum: data.pswdComplexNum,
      pswdComplexSplc: data.pswdComplexSplc,
      pswdComplexUcase: data.pswdComplexUcase,
      pswdExpiry: data.pswdExpiry,
      pswdReuseAft: data.pswdReuseAft,
      recordStatus: data.recordStatus,
      version: data.version,
      passwordGenerationType: data.passwordGenerationType,
    });
  }
}
